  1→#!/usr/bin/env node
  2→/**
  3→ * Claude Flow V3 Statusline Generator
  4→ * Displays real-time V3 implementation progress and system status
  5→ *
  6→ * Usage: node statusline.cjs [options]
  7→ *
  8→ * Options:
  9→ *   (default)   Safe multi-line output with collision zone avoidance
 10→ *   --single    Single-line output (completely avoids collision)
 11→ *   --unsafe    Legacy multi-line without collision avoidance
 12→ *   --legacy    Alias for --unsafe
 13→ *   --json      JSON output with pretty printing
 14→ *   --compact   JSON output without formatting
 15→ *
 16→ * Collision Zone Fix (Issue #985):
 17→ * Claude Code writes its internal status (e.g., "7s • 1p") at absolute
 18→ * terminal coordinates (columns 15-25 on second-to-last line). The safe
 19→ * mode pads the collision line with spaces to push content past column 25.
 20→ *
 21→ * IMPORTANT: This file uses .cjs extension to work in ES module projects.
 22→ * The require() syntax is intentional for CommonJS compatibility.
 23→ */
 24→
 25→/* eslint-disable @typescript-eslint/no-var-requires */
 26→const fs = require('fs');
 27→const path = require('path');
 28→const { execSync } = require('child_process');
 29→
 30→// Configuration
 31→const CONFIG = {
 32→  enabled: true,
 33→  showProgress: true,
 34→  showSecurity: true,
 35→  showSwarm: true,
 36→  showHooks: true,
 37→  showPerformance: true,
 38→  refreshInterval: 5000,
 39→  maxAgents: 15,
 40→  topology: 'hierarchical-mesh',
 41→};
 42→
 43→// Cross-platform helpers
 44→const isWindows = process.platform === 'win32';
 45→const nullDevice = isWindows ? 'NUL' : '/dev/null';
 46→
 47→// ANSI colors
 48→const c = {
 49→  reset: '\x1b[0m',
 50→  bold: '\x1b[1m',
 51→  dim: '\x1b[2m',
 52→  red: '\x1b[0;31m',
 53→  green: '\x1b[0;32m',
 54→  yellow: '\x1b[0;33m',
 55→  blue: '\x1b[0;34m',
 56→  purple: '\x1b[0;35m',
 57→  cyan: '\x1b[0;36m',
 58→  brightRed: '\x1b[1;31m',
 59→  brightGreen: '\x1b[1;32m',
 60→  brightYellow: '\x1b[1;33m',
 61→  brightBlue: '\x1b[1;34m',
 62→  brightPurple: '\x1b[1;35m',
 63→  brightCyan: '\x1b[1;36m',
 64→  brightWhite: '\x1b[1;37m',
 65→};
 66→
 67→// Get user info
 68→function getUserInfo() {
 69→  let name = 'user';
 70→  let gitBranch = '';
 71→  let modelName = 'Unknown';
 72→
 73→  try {
 74→    const gitUserCmd = isWindows
 75→      ? 'git config user.name 2>NUL || echo user'
 76→      : 'git config user.name 2>/dev/null || echo "user"';
 77→    const gitBranchCmd = isWindows
 78→      ? 'git branch --show-current 2>NUL || echo.'
 79→      : 'git branch --show-current 2>/dev/null || echo ""';
 80→    name = execSync(gitUserCmd, { encoding: 'utf-8' }).trim();
 81→    gitBranch = execSync(gitBranchCmd, { encoding: 'utf-8' }).trim();
 82→    if (gitBranch === '.') gitBranch = ''; // Windows echo. outputs a dot
 83→  } catch (e) {
 84→    // Ignore errors
 85→  }
 86→
 87→  // Auto-detect model from Claude Code's config
 88→  try {
 89→    const homedir = require('os').homedir();
 90→    const claudeConfigPath = path.join(homedir, '.claude.json');
 91→    if (fs.existsSync(claudeConfigPath)) {
 92→      const claudeConfig = JSON.parse(fs.readFileSync(claudeConfigPath, 'utf-8'));
 93→      // Try to find lastModelUsage - check current dir and parent dirs
 94→      let lastModelUsage = null;
 95→      const cwd = process.cwd();
 96→      if (claudeConfig.projects) {
 97→        // Try exact match first, then check if cwd starts with any project path
 98→        for (const [projectPath, projectConfig] of Object.entries(claudeConfig.projects)) {
 99→          if (cwd === projectPath || cwd.startsWith(projectPath + '/')) {
100→            lastModelUsage = projectConfig.lastModelUsage;
101→            break;
102→          }
103→        }
104→      }
105→      if (lastModelUsage) {
106→        const modelIds = Object.keys(lastModelUsage);
107→        if (modelIds.length > 0) {
108→          // Take the last model (most recently added to the object)
109→          // Or find the one with most tokens (most actively used this session)
110→          let modelId = modelIds[modelIds.length - 1];
111→          if (modelIds.length > 1) {
112→            // If multiple models, pick the one with most total tokens
113→            let maxTokens = 0;
114→            for (const id of modelIds) {
115→              const usage = lastModelUsage[id];
116→              const total = (usage.inputTokens || 0) + (usage.outputTokens || 0);
117→              if (total > maxTokens) {
118→                maxTokens = total;
119→                modelId = id;
120→              }
121→            }
122→          }
123→          // Parse model ID to human-readable name
124→          if (modelId.includes('opus')) modelName = 'Opus 4.5';
125→          else if (modelId.includes('sonnet')) modelName = 'Sonnet 4';
126→          else if (modelId.includes('haiku')) modelName = 'Haiku 4.5';
127→          else modelName = modelId.split('-').slice(1, 3).join(' ');
128→        }
129→      }
130→    }
131→  } catch (e) {
132→    // Fallback to Unknown if can't read config
133→  }
134→
135→  return { name, gitBranch, modelName };
136→}
137→
138→// Get learning stats from intelligence loop data (ADR-050)
139→function getLearningStats() {
140→  let patterns = 0;
141→  let sessions = 0;
142→  let trajectories = 0;
143→  let edges = 0;
144→  let confidenceMean = 0;
145→  let accessedCount = 0;
146→  let trend = 'STABLE';
147→
148→  // PRIMARY: Read from intelligence loop data files
149→  const dataDir = path.join(process.cwd(), '.claude-flow', 'data');
150→
151→  // 1. graph-state.json — authoritative node/edge counts
152→  const graphPath = path.join(dataDir, 'graph-state.json');
153→  if (fs.existsSync(graphPath)) {
154→    try {
155→      const graph = JSON.parse(fs.readFileSync(graphPath, 'utf-8'));
156→      patterns = graph.nodes ? Object.keys(graph.nodes).length : 0;
157→      edges = Array.isArray(graph.edges) ? graph.edges.length : 0;
158→    } catch (e) { /* ignore */ }
159→  }
160→
161→  // 2. ranked-context.json — confidence and access data
162→  const rankedPath = path.join(dataDir, 'ranked-context.json');
163→  if (fs.existsSync(rankedPath)) {
164→    try {
165→      const ranked = JSON.parse(fs.readFileSync(rankedPath, 'utf-8'));
166→      if (ranked.entries && ranked.entries.length > 0) {
167→        patterns = Math.max(patterns, ranked.entries.length);
168→        let confSum = 0;
169→        let accCount = 0;
170→        for (let i = 0; i < ranked.entries.length; i++) {
171→          confSum += (ranked.entries[i].confidence || 0);
172→          if ((ranked.entries[i].accessCount || 0) > 0) accCount++;
173→        }
174→        confidenceMean = confSum / ranked.entries.length;
175→        accessedCount = accCount;
176→      }
177→    } catch (e) { /* ignore */ }
178→  }
179→
180→  // 3. intelligence-snapshot.json — trend history
181→  const snapshotPath = path.join(dataDir, 'intelligence-snapshot.json');
182→  if (fs.existsSync(snapshotPath)) {
183→    try {
184→      const snapshot = JSON.parse(fs.readFileSync(snapshotPath, 'utf-8'));
185→      if (snapshot.history && snapshot.history.length >= 2) {
186→        const first = snapshot.history[0];
187→        const last = snapshot.history[snapshot.history.length - 1];
188→        const confDrift = (last.confidenceMean || 0) - (first.confidenceMean || 0);
189→        trend = confDrift > 0.01 ? 'IMPROVING' : confDrift < -0.01 ? 'DECLINING' : 'STABLE';
190→        sessions = Math.max(sessions, snapshot.history.length);
191→      }
192→    } catch (e) { /* ignore */ }
193→  }
194→
195→  // 4. auto-memory-store.json — fallback entry count
196→  if (patterns === 0) {
197→    const autoMemPath = path.join(dataDir, 'auto-memory-store.json');
198→    if (fs.existsSync(autoMemPath)) {
199→      try {
200→        const data = JSON.parse(fs.readFileSync(autoMemPath, 'utf-8'));
201→        patterns = Array.isArray(data) ? data.length : (data.entries ? data.entries.length : 0);
202→      } catch (e) { /* ignore */ }
203→    }
204→  }
205→
206→  // FALLBACK: Legacy memory.db file-size estimation
207→  if (patterns === 0) {
208→    const memoryPaths = [
209→      path.join(process.cwd(), '.swarm', 'memory.db'),
210→      path.join(process.cwd(), '.claude', 'memory.db'),
211→      path.join(process.cwd(), 'data', 'memory.db'),
212→    ];
213→    for (let j = 0; j < memoryPaths.length; j++) {
214→      if (fs.existsSync(memoryPaths[j])) {
215→        try {
216→          const dbStats = fs.statSync(memoryPaths[j]);
217→          patterns = Math.floor(dbStats.size / 1024 / 2);
218→          break;
219→        } catch (e) { /* ignore */ }
220→      }
221→    }
222→  }
223→
224→  // Session count from session files
225→  const sessionsPath = path.join(process.cwd(), '.claude', 'sessions');
226→  if (fs.existsSync(sessionsPath)) {
227→    try {
228→      const sessionFiles = fs.readdirSync(sessionsPath).filter(f => f.endsWith('.json'));
229→      sessions = Math.max(sessions, sessionFiles.length);
230→    } catch (e) { /* ignore */ }
231→  }
232→
233→  trajectories = Math.floor(patterns / 5);
234→
235→  return { patterns, sessions, trajectories, edges, confidenceMean, accessedCount, trend };
236→}
237→
238→// Get V3 progress from learning state (grows as system learns)
239→function getV3Progress() {
240→  const learning = getLearningStats();
241→
242→  // DDD progress based on actual learned patterns
243→  // New install: 0 patterns = 0/5 domains, 0% DDD
244→  // As patterns grow: 10+ patterns = 1 domain, 50+ = 2, 100+ = 3, 200+ = 4, 500+ = 5
245→  let domainsCompleted = 0;
246→  if (learning.patterns >= 500) domainsCompleted = 5;
247→  else if (learning.patterns >= 200) domainsCompleted = 4;
248→  else if (learning.patterns >= 100) domainsCompleted = 3;
249→  else if (learning.patterns >= 50) domainsCompleted = 2;
250→  else if (learning.patterns >= 10) domainsCompleted = 1;
251→
252→  const totalDomains = 5;
253→  const dddProgress = Math.min(100, Math.floor((domainsCompleted / totalDomains) * 100));
254→
255→  return {
256→    domainsCompleted,
257→    totalDomains,
258→    dddProgress,
259→    patternsLearned: learning.patterns,
260→    sessionsCompleted: learning.sessions
261→  };
262→}
263→
264→// Get security status based on actual scans
265→function getSecurityStatus() {
266→  // Check for security scan results in memory
267→  const scanResultsPath = path.join(process.cwd(), '.claude', 'security-scans');
268→  let cvesFixed = 0;
269→  const totalCves = 3;
270→
271→  if (fs.existsSync(scanResultsPath)) {
272→    try {
273→      const scans = fs.readdirSync(scanResultsPath).filter(f => f.endsWith('.json'));
274→      // Each successful scan file = 1 CVE addressed
275→      cvesFixed = Math.min(totalCves, scans.length);
276→    } catch (e) {
277→      // Ignore
278→    }
279→  }
280→
281→  // Also check .swarm/security for audit results
282→  const auditPath = path.join(process.cwd(), '.swarm', 'security');
283→  if (fs.existsSync(auditPath)) {
284→    try {
285→      const audits = fs.readdirSync(auditPath).filter(f => f.includes('audit'));
286→      cvesFixed = Math.min(totalCves, Math.max(cvesFixed, audits.length));
287→    } catch (e) {
288→      // Ignore
289→    }
290→  }
291→
292→  const status = cvesFixed >= totalCves ? 'CLEAN' : cvesFixed > 0 ? 'IN_PROGRESS' : 'PENDING';
293→
294→  return {
295→    status,
296→    cvesFixed,
297→    totalCves,
298→  };
299→}
300→
301→// Get swarm status
302→function getSwarmStatus() {
303→  let activeAgents = 0;
304→  let coordinationActive = false;
305→
306→  try {
307→    if (isWindows) {
308→      // Windows: use tasklist and findstr
309→      const ps = execSync('tasklist 2>NUL | findstr /I "agentic-flow" 2>NUL | find /C /V "" 2>NUL || echo 0', { encoding: 'utf-8' });
310→      activeAgents = Math.max(0, parseInt(ps.trim()) || 0);
311→    } else {
312→      const ps = execSync('ps aux 2>/dev/null | grep -c agentic-flow || echo "0"', { encoding: 'utf-8' });
313→      activeAgents = Math.max(0, parseInt(ps.trim()) - 1);
314→    }
315→    coordinationActive = activeAgents > 0;
316→  } catch (e) {
317→    // Ignore errors - default to 0 agents
318→  }
319→
320→  return {
321→    activeAgents,
322→    maxAgents: CONFIG.maxAgents,
323→    coordinationActive,
324→  };
325→}
326→
327→// Get system metrics (dynamic based on actual state)
328→function getSystemMetrics() {
329→  let memoryMB = 0;
330→  let subAgents = 0;
331→
332→  try {
333→    if (isWindows) {
334→      // Windows: use tasklist for memory info, fallback to process.memoryUsage
335→      // tasklist memory column is complex to parse, use Node.js API instead
336→      memoryMB = Math.floor(process.memoryUsage().heapUsed / 1024 / 1024);
337→    } else {
338→      const mem = execSync('ps aux | grep -E "(node|agentic|claude)" | grep -v grep | awk \'{sum += $6} END {print int(sum/1024)}\'', { encoding: 'utf-8' });
339→      memoryMB = parseInt(mem.trim()) || 0;
340→    }
341→  } catch (e) {
342→    // Fallback
343→    memoryMB = Math.floor(process.memoryUsage().heapUsed / 1024 / 1024);
344→  }
345→
346→  // Get learning stats for intelligence %
347→  const learning = getLearningStats();
348→
349→  // Intelligence % from REAL intelligence loop data (ADR-050)
350→  // Composite: 40% confidence mean + 30% access ratio + 30% pattern density
351→  let intelligencePct = 0;
352→  if (learning.confidenceMean > 0 || (learning.patterns > 0 && learning.accessedCount > 0)) {
353→    const confScore = Math.min(100, Math.floor(learning.confidenceMean * 100));
354→    const accessRatio = learning.patterns > 0 ? (learning.accessedCount / learning.patterns) : 0;
355→    const accessScore = Math.min(100, Math.floor(accessRatio * 100));
356→    const densityScore = Math.min(100, Math.floor(learning.patterns / 5));
357→    intelligencePct = Math.floor(confScore * 0.4 + accessScore * 0.3 + densityScore * 0.3);
358→  }
359→  // Fallback: legacy pattern count
360→  if (intelligencePct === 0 && learning.patterns > 0) {
361→    intelligencePct = Math.min(100, Math.floor(learning.patterns / 10));
362→  }
363→
364→  // Context % based on session history
365→  const contextPct = Math.min(100, Math.floor(learning.sessions * 5));
366→
367→  // Count active sub-agents from process list
368→  try {
369→    if (isWindows) {
370→      // Windows: use tasklist and findstr for agent counting
371→      const agents = execSync('tasklist 2>NUL | findstr /I "claude-flow" 2>NUL | find /C /V "" 2>NUL || echo 0', { encoding: 'utf-8' });
372→      subAgents = Math.max(0, parseInt(agents.trim()) || 0);
373→    } else {
374→      const agents = execSync('ps aux 2>/dev/null | grep -c "claude-flow.*agent" || echo "0"', { encoding: 'utf-8' });
375→      subAgents = Math.max(0, parseInt(agents.trim()) - 1);
376→    }
377→  } catch (e) {
378→    // Ignore - default to 0
379→  }
380→
381→  return {
382→    memoryMB,
383→    contextPct,
384→    intelligencePct,
385→    subAgents,
386→  };
387→}
388→
389→// Generate progress bar
390→function progressBar(current, total) {
391→  const width = 5;
392→  const filled = Math.round((current / total) * width);
393→  const empty = width - filled;
394→  return '[' + '\u25CF'.repeat(filled) + '\u25CB'.repeat(empty) + ']';
395→}
