        newArgs[bodyIndex] = '--body-file';
        newArgs[bodyIndex + 1] = tmpFile;
      }

      // Execute safely using array form to prevent shell injection
      const ghArgs = [command, subcommand, ...newArgs];
      console.log(`Executing: gh ${ghArgs.join(' ')}`);

      execFileSync('gh', ghArgs, {
        stdio: 'inherit',
        timeout: 30000 // 30 second timeout
      });

    } catch (error) {
      console.error('Error:', error.message);
      process.exit(1);
    } finally {
      // Clean up
      try {
        unlinkSync(tmpFile);
      } catch (e) {
        // Ignore cleanup errors
      }
    }
  } else {
    // No body content, execute normally using array form
    execFileSync('gh', args, { stdio: 'inherit' });
  }
} else {
  // Other commands, execute normally
  execSync(`gh ${args.join(' ')}`, { stdio: 'inherit' });
}

