// Minimal safety net — primary protection comes from Claude Code's
// built-in permission model. This catches obvious destructive patterns only.
const dangerous = [
  'rm -rf /', 'rm -rf ~/', 'rm -rf ~',
  'format c:', 'del /s /q c:\\', ':(){:|:&};:',
  'curl.*|.*sh', 'wget.*|.*sh',
  '--dangerously',
  '> /dev/sd', 'mkfs', 'dd if='
];

